import json

transactions = [
    {"category": "Rent", "amount": 2500, "description": "Monthly rent", "account": "checking"},
    {"category": "Utilities", "amount": 150, "description": "Utilities (electricity)", "account": "checking"},
    {"category": "Internet/Phone", "amount": 100, "description": "Internet/Phone", "account": "checking"},
    {"category": "Office supplies", "amount": 75, "description": "Office supplies", "account": "checking"}
]

created = []
for t in transactions:
    resp = json.loads(tools.create_transaction(
        transaction_type="expense",
        category=t["category"],
        amount=t["amount"],
        description=t["description"],
        account=t["account"]
    ))
    if "error" in resp:
        raise Exception(resp["error"])
    created.append(resp)

summary = json.loads(tools.get_financial_summary())
if "error" in summary:
    raise Exception(summary["error"])

balance = json.loads(tools.get_account_balance("checking"))
if "error" in balance:
    raise Exception(balance["error"])

state = json.loads(tools.get_state_summary())
if "error" in state:
    raise Exception(state["error"])

total_expenses = summary.get("total_expenses")
if total_expenses is None:
    total_expenses = sum([t["amount"] for t in transactions])

remaining_balance = balance.get("balance")
if remaining_balance is None:
    raise Exception("Unable to determine checking account balance from tool output.")

result = {
    "message": "Monthly expenses recorded successfully.",
    "expenses_recorded": [
        {"category": t["category"], "amount": t["amount"], "account": t["account"]}
        for t in transactions
    ],
    "summary": {
        "total_expenses": total_expenses,
        "checking_remaining_balance": remaining_balance
    },
    "state_verified": True,
    "state_snapshot": state
}

