if "error" in r:
    raise Exception(r["error"])

# Month 2
invoice_resp = json.loads(tools.create_invoice(
    "BigCorp",
    [{"description": "Consulting 100hrs @ $150/hr", "quantity": 100, "price": 150}],
    due_days=30
))
if "error" in invoice_resp:
    raise Exception(invoice_resp["error"])

invoice_id = ""
if "invoice" in invoice_resp and isinstance(invoice_resp["invoice"], dict):
    invoice_id = invoice_resp["invoice"].get("id", "")
if not invoice_id:
    raise Exception("Missing invoice ID after create_invoice.")

r = json.loads(tools.update_invoice_status(invoice_id, "sent"))
if "error" in r:
    raise Exception(r["error"])

r = json.loads(tools.create_transaction("income", "product sales", 8000, "Month 2 product sales income"))
if "error" in r:
    raise Exception(r["error"])
r = json.loads(tools.create_transaction("expense", "rent", 2500, "Month 2 rent"))
if "error" in r:
    raise Exception(r["error"])
r = json.loads(tools.create_transaction("expense", "marketing", 1200, "Month 2 marketing"))
if "error" in r:
    raise Exception(r["error"])
r = json.loads(tools.create_transaction("expense", "software", 400, "Month 2 software"))
if "error" in r:
    raise Exception(r["error"])

# Month 3
r = json.loads(tools.update_invoice_status(invoice_id, "paid"))
if "error" in r:
    raise Exception(r["error"])

r = json.loads(tools.create_transaction("income", "consulting", 6000, "Month 3 consulting income"))
if "error" in r:
    raise Exception(r["error"])
r = json.loads(tools.create_transaction("expense", "rent", 2500, "Month 3 rent"))
if "error" in r:
    raise Exception(r["error"])
r = json.loads(tools.create_transaction("expense", "utilities", 250, "Month 3 utilities"))
if "error" in r:
    raise Exception(r["error])
r = json.loads(tools.create_transaction("expense", "travel", 800, "Month 3 travel"))
if "error" in r:
    raise Exception(r["error"])

# Verify final state after all operations
state = json.loads(tools.get_state_summary())
if "error" in state:
    raise Exception(state["error"])

# Pull reporting datasets
financial = json.loads(tools.get_financial_summary())
if "error" in financial:
    raise Exception(financial["error"])

transactions_resp = json.loads(tools.get_transactions())
if "error" in transactions_resp:
    raise Exception(transactions_resp["error"])
transactions = transactions_resp.get("transactions", [])

invoices_resp = json.loads(tools.get_invoices())
if "error" in invoices_resp:
    raise Exception(invoices_resp["error"])
invoices = invoices_resp.get("invoices", [])

# Compute breakdowns from transaction ledger
income_by_category = {}
expense_by_category = {}
for tx in transactions:
    ttype = tx.get("transaction_type")
    cat = tx.get("category", "uncategorized")
    amt = tx.get("amount", 0)
    if ttype == "income":
        income_by_category[cat] = income_by_category.get(cat, 0) + amt
    elif ttype == "expense":
        expense_by_category[cat] = expense_by_category.get(cat, 0) + amt

total_income = sum(income_by_category.values())
total_expenses = sum(expense_by_category.values())
net_profit = total_income - total_expenses

# Invoice statuses and receivables
invoice_statuses = {}
outstanding_receivables = 0
for inv in invoices:
    status = inv.get("status", "unknown")
    invoice_statuses[status] = invoice_statuses.get(status, 0) + 1
    total = inv.get("total", 0)
    paid_amount = inv.get("paid_amount", 0)
    remaining = total - paid_amount
    if remaining > 0 and status != "paid":
        outstanding_receivables += remaining

# Discover valid account names from state summary to avoid unknown account errors
account_balances = {}
accounts_obj = state.get("accounts", {})
if isinstance(accounts_obj, dict):
    for account_name in accounts_obj:
        bal = json.loads(tools.get_account_balance(account_name))
        if "error" not in bal:
            account_balances[account_name] = bal

result = {
    "message": "Quarter simulation completed and quarter-end report generated.",
    "quarter_end_report": {
        "total_income": total_income,
        "income_breakdown_by_category": income_by_category,
        "total_expenses": total_expenses,
        "expense_breakdown_by_category": expense_by_category,
        "net_profit": net_profit,
        "number_of_invoices": len(invoices),
        "invoice_statuses": invoice_statuses,
        "all_account_balances": account_balances,
        "outstanding_receivables": outstanding_receivables
    },
    "validation": {
        "state_summary_checked": True,
        "invoice_id_used": invoice_id
    },
    "supporting_outputs": {
        "financial_summary": financial,
        "state_summary": state
    }
}

