    if inv_id is None:
        raise Exception("Invalid invoice ID for status update to sent")
    sent_resp = json.loads(tools.update_invoice_status(inv_id, "sent"))
    if "error" in sent_resp:
        raise Exception(sent_resp["error"])

startup_id = startup_invoice["id"]
if startup_id is None:
    raise Exception("Invalid StartupX invoice ID for partial payment")
pp_startup = json.loads(tools.record_partial_payment(startup_id, 7000))
