    raise Exception(pp_startup["error"])

retail_id = retail_invoice["id"]
if retail_id is None:
    raise Exception("Invalid RetailCo invoice ID for paid update")
paid_retail = json.loads(tools.update_invoice_status(retail_id, "paid"))
if "error" in paid_retail:
    raise Exception(paid_retail["error"])

tech_id = tech_invoice["id"]
if tech_id is None:
    raise Exception("Invalid TechGiant invoice ID for partial payment")
pp_tech = json.loads(tools.record_partial_payment(tech_id, 10000))
if "error" in pp_tech:
    raise Exception(pp_tech["error"])

invoices_resp = json.loads(tools.get_invoices())
if "error" in invoices_resp:
    raise Exception(invoices_resp["error"])
invoices = invoices_resp.get("invoices", [])

summary_resp = json.loads(tools.get_financial_summary())
if "error" in summary_resp:
    raise Exception(summary_resp["error"])

state_resp = json.loads(tools.get_state_summary())
if "error" in state_resp:
    raise Exception(state_resp["error"])

target_ids = [startup_id, retail_id, tech_id]
report_rows = []
outstanding = 0.0
follow_up = []

for inv in invoices:
    if inv.get("id") in target_ids:
        total = float(inv.get("total", 0))
        paid = float(inv.get("paid_amount", 0))
        remaining = float(inv.get("remaining_amount", 0))
        status = inv.get("status", "")
        row = {
            "id": inv.get("id"),
            "client": inv.get("client_name"),
            "status": status,
            "total": total,
            "paid": paid,
            "remaining": remaining
        }
        report_rows.append(row)
        outstanding += remaining
        if remaining > 0 and status != "paid":
            follow_up.append({
                "id": inv.get("id"),
                "client": inv.get("client_name"),
                "status": status,
                "remaining": remaining
            })

total_income = float(summary_resp.get("income", 0))

result = {
    "operations_completed": {
        "invoices_created": [startup_id, retail_id, tech_id],
        "all_marked_sent": True,
        "startupx_partial_payment_recorded": 7000,
        "retailco_marked_paid": True,
        "techgiant_partial_payment_recorded": 10000
    },
    "invoice_report": report_rows,
    "totals": {
        "outstanding_receivables": outstanding,
        "payments_received_income": total_income
    },
    "follow_up_needed": follow_up,
    "state_summary_check": state_resp
}

