paid_retail = json.loads(tools.update_invoice_status(retail_id, "paid"))
if "error" in paid_retail:
    raise Exception(paid_retail["error"])

tech_id = tech_invoice["id"]
if tech_id is None:
    raise Exception("Invalid TechGiant invoice ID for partial payment")
pp_tech = json.loads(tools.record_partial_payment(tech_id, 10000))
if "error" in pp_tech:
    raise Exception(pp_tech["error"])

invoices_resp = json.loads(tools.get_invoices())
if "error" in invoices_resp:
    raise Exception(invoices_resp["error"])
invoices = invoices_resp.get("invoices", [])

summary_resp = json.loads(tools.get_financial_summary())
if "error" in summary_resp:
