follow_up = []

for inv in invoices:
    if inv.get("id") in target_ids:
        total = float(inv.get("total", 0))
        paid = float(inv.get("paid_amount", 0))
        remaining = float(inv.get("remaining_amount", 0))
        status = inv.get("status", "")
        row = {
